    };
}

/// Log captured output for debugging.
pub fn debug_output(label: &str, output: &str) {
    if is_verbose() {
        eprintln!("\n=== {} (raw) ===\n{}\n=== {} (stripped) ===\n{}\n=== END ===\n",
            label, output, label, strip_ansi_codes(output));
    }
